  for r in
    select value as question
    from jsonb_array_elements($questions$[{"text":"როდის შეიძლება გათავისუფლდეს პირი სისხლისსამართლებრივი პასუხისმგებლობისგან ვითარების შეცვლის გამო სსკ-ის 61-ე მუხლის შესაბამისად?","options":["A. თუ საქმის განხილვისას დადგინდა, რომ ვითარების შეცვლის გამო ჩადენილმა ქმედებამ დაკარგა საზოგადოებრივი საშიშროება ან პირმა შეწყვიტა საზოგადოებრივი საშიშროება.","B. თუ გამოძიებისას დადგინდა, რომ პირმა სრულად აანაზღაურა მიყენებული ზიანი და აღარ წარმოადგენს საზოგადოებრივ საფრთხეს.","C. თუ საქმის განხილვისას დადგინდა, რომ ვითარების შეცვლის გამო ქმედებამ დაკარგა საზოგადოებრივი საშიშროება, ხოლო პირმა სრულად აანაზღაურა მატერიალური ზიანი.","D. თუ გამოძიებისას ან საქმის განხილვისას დადგინდა, რომ პირმა ჩაიდინა ნაკლებად მძიმე დანაშაული და შეცვლილი ვითარების გამო იგი აღარ არის საშიში."],"correct_option":"A","explanation":"სსკ-ის 61-ე მუხლის თანახმად, პირი შეიძლება გათავისუფლდეს სისხლისსამართლებრივი პასუხისმგებლობისგან, თუ დადგინდა, რომ ვითარების შეცვლის გამო ჩადენილმა ქმედებამ დაკარგა საზოგადოებრივი საშიშროება ან ამ პირმა შეწყვიტა საზოგადოებრივი საშიშროება.","law_article":"მუხლი 61"},{"text":"რა ვადებში ხდება სისხლისსამართლებრივი პასუხისმგებლობისგან გათავისუფლება ხანდაზმულობის ვადის გასვლის გამო ნაკლებად მძიმე დანაშაულის ჩადენისას სსკ-ის 62-ე მუხლის 1-ლი ნაწილის „ა“ ქვეპუნქტის მიხედვით?","options":["A. 6 წელი ნაკლებად მძიმე დანაშაულის ჩადენიდან.","B. 2 წელი ნაკლებად მძიმე დანაშაულის ჩადენიდან.","C. 5 წელი ნაკლებად მძიმე დანაშაულის ჩადენიდან.","D. 4 წელი ნაკლებად მძიმე დანაშაულის ჩადენიდან."],"correct_option":"A","explanation":"სსკ-ის 62-ე მუხლის 1-ლი ნაწილის „ა“ ქვეპუნქტის თანახმად, ნაკლებად მძიმე დანაშაულის ჩადენიდან 6 წლის გასვლის შემდეგ პირი თავისუფლდება სისხლისსამართლებრივი პასუხისმგებლობისგან.","law_article":"მუხლი 62, ნაწილი 1, ქვეპუნქტი ა"},{"text":"რა ვადებში ხდება სისხლისსამართლებრივი პასუხისმგებლობისგან გათავისუფლება ხანდაზმულობის ვადის გასვლის გამო მძიმე და განსაკუთრებით მძიმე დანაშაულის ჩადენისას სსკ-ის 62-ე მუხლის 1-ლი ნაწილის შესაბამისად?","options":["A. 10 წელი – მძიმე დანაშაულის ჩადენიდან; 25 წელი – განსაკუთრებით მძიმე დანაშაულის ჩადენიდან.","B. 10 წელი – მძიმე დანაშაულის ჩადენიდან; 15 წელი – განსაკუთრებით მძიმე დანაშაულის ჩადენიდან.","C. 8 წელი – მძიმე დანაშაულის ჩადენიდან; 20 წელი – განსაკუთრებით მძიმე დანაშაულის ჩადენიდან.","D. 12 წელი – მძიმე დანაშაულის ჩადენიდან; 25 წელი – განსაკუთრებით მძიმე დანაშაულის ჩადენიდან."],"correct_option":"A","explanation":"სსკ-ის 62-ე მუხლის 1-ლი ნაწილის „ბ“ და „გ“ ქვეპუნქტების მიხედვით, ხანდაზმულობის ვადა შეადგენს 10 წელს მძიმე დანაშაულისთვის და 25 წელს განსაკუთრებით მძიმე დანაშაულისთვის.","law_article":"მუხლი 62, ნაწილი 1, ქვეპუნქტები ბ, გ"},{"text":"როდის აჩერებს დინებას ხანდაზმულობის ვადა სსკ-ის 62-ე მუხლის მე-3 ნაწილის მიხედვით?","options":["A. თუ დამნაშავე მიემალა გამოძიებას ან სასამართლოს.","B. თუ დამნაშავემ ხანდაზმულობის ვადის გასვლამდე ჩაიდინა ახალი განზრახი დანაშაული.","C. თუ გამოძიების პროცესში შეჩერდა სისხლისსამართლებრივი დევნა ექსპერტიზის დანიშვნის გამო.","D. თუ დამნაშავე დროებით გამოცხადდა ქმედუუნაროდ ან მძიმედ დაავადდა."],"correct_option":"A","explanation":"სსკ-ის 62-ე მუხლის მე-3 ნაწილის თანახმად, ხანდაზმულობის ვადის დინება შეჩერდება, თუ დამნაშავე მიემალა გამოძიებას ან სასამართლოს. დინება განახლდება დამნაშავის დაკავების ან ბრალის აღიარებით გამოცხადების მომენტიდან.","law_article":"მუხლი 62, ნაწილი 3"},{"text":"რა პირობებით არის დასაშვები სასჯელისაგან პირობით ვადამდე გათავისუფლება სსკ-ის 63-ე მუხლის მიხედვით ნაკლებად მძიმე დანაშაულისთვის მსჯავრდებული პირის მიმართ?","options":["A. თუ მან ფაქტობრივად მოიხადა მოსახდელი სასჯელის ვადის არანაკლებ ერთი მესამედი.","B. თუ მან ფაქტობრივად მოიხადა მოსახდელი სასჯელის ვადის არანაკლებ ნახევარი.","C. თუ მან ფაქტობრივად მოიხადა მოსახდელი სასჯელის ვადის არანაკლებ ორი მესამედი.","D. თუ მან ფაქტობრივად მოიხადა მოსახდელი სასჯელის ვადის არანაკლებ სამი მეოთხედი."],"correct_option":"A","explanation":"სსკ-ის 63-ე მუხლის მიხედვით, ნაკლებად მძიმე დანაშაულისთვის მსჯავრდებული პირის სასჯელისაგან პირობით ვადამდე გათავისუფლება დასაშვებია, თუ მან მოიხადა სასჯელის ვადის არანაკლებ 1/3.","law_article":"მუხლი 63"},{"text":"რა ნაწილი უნდა იყოს ფაქტობრივად მოხდილი მძიმე და განსაკუთრებით მძიმე დანაშაულისთვის სასჯელისაგან პირობით ვადამდე გასათავისუფლებლად სსკ-ის 63-ე მუხლის თანახმად?","options":["A. მძიმე დანაშაულისათვის – არანაკლებ ნახევარი; განსაკუთრებით მძიმე დანაშაულისათვის – არანაკლებ ორი მესამედი.","B. მძიმე დანაშაულისათვის – არანაკლებ ერთი მესამედი; განსაკუთრებით მძიმე დანაშაულისათვის – არანაკლებ ნახევარი.","C. მძიმე დანაშაულისათვის – არანაკლებ ორი მესამედი; განსაკუთრებით მძიმე დანაშაულისათვის – არანაკლებ სამი მეოთხედი.","D. მძიმე დანაშაულისათვის – არანაკლებ ნახევარი; განსაკუთრებით მძიმე დანაშაულისათვის – არანაკლებ სამი მეოთხედი."],"correct_option":"A","explanation":"სსკ-ის 63-ე მუხლის შესაბამისად, პირობით ვადამდე გათავისუფლება დასაშვებია: მძიმე დანაშაულისას – სასჯელის არანაკლებ 1/2-ის, ხოლო განსაკუთრებით მძიმე დანაშაულისას – არანაკლებ 2/3-ის მოხდის შემდეგ.","law_article":"მუხლი 63"},{"text":"რა ვადაში შეიძლება შეიცვალოს სასჯელის აუმოსახდელი ნაწილი უფრო მსუბუქი სახის სასჯელით სსკ-ის 64-ე მუხლის მიხედვით ნაკლებად მძიმე დანაშაულის ჩადენისას?","options":["A. მოსახდელი სასჯელის ვადის არანაკლებ ერთი მესამედის მოხდის შემდეგ.","B. მოსახდელი სასჯელის ვადის არანაკლებ ნახევრის მოხდის შემდეგ.","C. მოსახდელი სასჯელის ვადის არანაკლებ ერთი მეოთხედის მოხდის შემდეგ.","D. მოსახდელი სასჯელის ვადის არანაკლებ ორი მესამედის მოხდის შემდეგ."],"correct_option":"A","explanation":"სსკ-ის 64-ე მუხლის მიხედვით, სასჯელის აუმოსახდელი ნაწილი უფრო მსუბუქი სახის სასჯელით შეიძლება შეიცვალოს ნაკლებად მძიმე დანაშაულისათვის სასჯელის არანაკლებ 1/3-ის მოხდის შემდეგ.","law_article":"მუხლი 64"},{"text":"რა პირობებით გამოიყენება პირობითი მსჯავრი სსკ-ის 67-ე მუხლის 1-ლი ნაწილის თანახმად?","options":["A. თუ სასამართლო დაასკვნის, რომ დამნაშავის გამოსწორება შესაძლებელია სასჯელის რეალურად მოუხდელად, იგი დაადგენს, რომ დანიშნული სასჯელი ჩაითვალოს პირობითად.","B. თუ პირმა პირველად ჩაიდინა ნაკლებად მძიმე დანაშაული და სრულად აანაზღაურა მიყენებული ზიანი განაჩენის გამოტანამდე.","C. თუ პირმა ჩაიდინა დანაშაული აფექტის მდგომარეობაში და დაზარალებული არ მოითხოვს სასჯელის რეალურად მოხდას.","D. თუ სასამართლო მიიჩნევს, რომ ბრალდებულის მიერ ჩადენილი დანაშაული არ ითვალისწინებს 5 წელზე მეტი ვადით თავისუფლების აღკვეთას."],"correct_option":"A","explanation":"სსკ-ის 67-ე მუხლის 1-ლი ნაწილის თანახმად, თუ გამასწორებელი სამუშაოს, სამხედრო პირის სამსახურებრივი შეზღუდვის, შინაპატიმრობის ან ვადიანი თავისუფლების აღკვეთის დანიშვნისას სასამართლო დაასკვნის, რომ დამნაშავის გამოსწორება შესაძლებელია სასჯელის რეალურად მოუხდელად, იგი დაადგენს, რომ დანიშნული სასჯელი ჩაითვალოს პირობითად.","law_article":"მუხლი 67, ნაწილი 1"},{"text":"როგორ განისაზღვრება გამოსაცდელი ვადა პირობითი მსჯავრის დანიშვნისას სსკ-ის 67-ე მუხლის მე-3 ნაწილის მიხედვით?","options":["A. გამოსაცდელი ვადა წესდება 1 წლიდან 5 წლამდე.","B. გამოსაცდელი ვადა წესდება 6 თვიდან 3 წლამდე.","C. გამოსაცდელი ვადა შეადგენს ზუსტად დანიშნული სასჯელის ორმაგ ოდენობას.","D. გამოსაცდელი ვადა წესდება 2 წლიდან 7 წლამდე."],"correct_option":"A","explanation":"სსკ-ის 67-ე მუხლის მე-3 ნაწილის შესაბამისად, პირობითი მსჯავრის დანიშვნისას გამოსაცდელი ვადა წესდება 1 წლიდან 5 წლამდე.","law_article":"მუხლი 67, ნაწილი 3"},{"text":"რა უფლება აქვს სასამართლოს პირობითი მსჯავრის გაუქმებისა და ნასამართლობის მოხსნის შესახებ სსკ-ის 68-ე მუხლის 1-ლი ნაწილის მიხედვით?","options":["A. თუ პირობით მსჯავრდებულმა გამოსაცდელი ვადის არანაკლებ ნახევრის გასვლის შემდეგ ყოფაქცევით დაამტკიცა გამოსწორება, სასამართლოს შეუძლია გაუქმოს პირობითი მსჯავრი და მოუხსნას ნასამართლობა.","B. თუ პირობით მსჯავრდებულმა გამოსაცდელი ვადის არანაკლებ ერთი მესამედის გასვლის შემდეგ სრულად აანაზღაურა ზიანი, სასამართლო ვალდებულია მოუხსნას ნასამართლობა.","C. თუ პირობით მსჯავრდებულს გამოსაცდელი ვადის 2/3-ის განმავლობაში არ ჩაუდენია ადმინისტრაციული სამართალდარღვევა, პირობითი მსჯავრი ავტომატურად უქმდება.","D. თუ პირობით მსჯავრდებულმა გამოსაცდელი ვადის ნახევრის გასვლის შემდეგ ჩაიდინა გაუფრთხილებლობითი დანაშაული, სასამართლო აგრძელებს ვადას 2 წლით."],"correct_option":"A","explanation":"სსკ-ის 68-ე მუხლის 1-ლი ნაწილის თანახმად, თუ პირობით მსჯავრდებულმა გამოსაცდელი ვადის არანაკლებ ნახევრის გასვლის შემდეგ სანიმუშო ქცევით და შრომით დაამტკიცა თავისი გამოსწორება, სასამართლოს შეუძლია გაუქმოს პირობითი მსჯავრი და მოუხსნას ნასამართლობა.","law_article":"მუხლი 68, ნაწილი 1"},{"text":"რა სამართლებრივი შედეგი დგება, თუ პირობით მსჯავრდებული გამოსაცდელი ვადის განმავლობაში სისტემატურად ან უხეშად არღვევს დაკისრებულ მოვალეობას სსკ-ის 68-ე მუხლის მე-2 ნაწილის მიხედვით?","options":["A. სასამართლოს შეუძლია გაუქმოს პირობითი მსჯავრი და აღასრულოს განაჩენით დანიშნული სასჯელი.","B. სასამართლო ვალდებულია გაუზარდოს გამოსაცდელი ვადა 3 წლამდე, მაგრამ არაუმეტეს კანონით დადგენილი ზღვრისა.","C. პირობითი მსჯავრი ავტომატურად უქმდება და პირს ეკისრება დამატებითი ჯარიმა.","D. სასამართლო პირობით მსჯავრს ცვლის შინაპატიმრობით გამოსაცდელი ვადის დარჩენილი პერიოდით."],"correct_option":"A","explanation":"სსკ-ის 68-ე მუხლის მე-2 ნაწილის თანახმად, მოვალეობის სისტემატურად ან უხეშად შეუსრულებლობისას სასამართლოს შეუძლია გაუქმოს პირობითი მსჯავრი და აღასრულოს დანიშნული სასჯელი.","law_article":"მუხლი 68, ნაწილი 2"},{"text":"რა ვადით შეიძლება გადაუვადდეს სასჯელის მოხდა ორსულ ქალს ან დედას, რომელსაც ჰყავს მცირეწლოვანი შვილი სსკ-ის 69-ე მუხლის 1-ლი ნაწილის მიხედვით?","options":["A. ბავშვის 5 წლის ასაკის მიღწევამდე.","B. ბავშვის 3 წლის ასაკის მიღწევამდე.","C. ბავშვის 8 წლის ასაკის მიღწევამდე.","D. ბავშვის სრულწლოვანების მიღწევამდე."],"correct_option":"A","explanation":"სსკ-ის 69-ე მუხლის 1-ლი ნაწილის მიხედვით, მსჯავრდებულ ორსულ ქალს ან დედას შვილის 5 წლის ასაკის მიღწევამდე სასამართლომ შეიძლება გადაუვადოს სასჯელის მოხდა.","law_article":"მუხლი 69, ნაწილი 1"},{"text":"რომელი დანაშაულისთვის მსჯავრდებულ პირს არ შეიძლება გადაუვადდეს სასჯელის მოხდა ორსულობის ან მცირეწლოვანი შვილის ყოლის გამო სსკ-ის 69-ე მუხლის 1-ლი ნაწილის შესაბამისად?","options":["A. პირს, რომელსაც სასჯელის სახედ განსაზღვრული აქვს თავისუფლების აღკვეთა 5 წელზე მეტი ვადით განსაკუთრებით მძიმე დანაშაულისათვის.","B. პირს, რომელსაც სასჯელის სახედ განსაზღვრული აქვს თავისუფლების აღკვეთა 3 წელზე მეტი ვადით მძიმე დანაშაულისათვის.","C. პირს, რომელმაც დანაშაული ჩაიდინა რეციდივის დროს, მიუხედავად დანაშაულის კატეგორიისა.","D. პირს, რომელსაც დაკისრებული აქვს ჯარიმა ან საზოგადოებისათვის სასარგებლო შრომა."],"correct_option":"A","explanation":"სსკ-ის 69-ე მუხლის 1-ლი ნაწილის თანახმად, სასჯელის გადავადება არ გამოიყენება იმ პირის მიმართ, რომელსაც მიესაჯა თავისუფლების აღკვეთა 5 წელზე მეტი ვადით განსაკუთრებით მძიმე დანაშაულისათვის.","law_article":"მუხლი 69, ნაწილი 1"},{"text":"რა საფუძვლით შეიძლება გათავისუფლდეს მსჯავრდებული სასჯელის შემდგომი მოხდისაგან სსკ-ის 70-ე მუხლის მიხედვით?","options":["A. მძიმე დაავადების გამო, რაც დაბრკოლებას ქმნის სასჯელის მოხდისათვის.","B. ფინანსური გაკოტრების ან ოჯახური მძიმე ვითარების გამო.","C. საპენსიო ასაკის მიღწევისა და შრომისუნარიანობის სრული დაკარგვის გამო.","D. დაზარალებულთან სრული შერიგებისა და სამოქალაქო სარჩელის ცნობის გამო."],"correct_option":"A","explanation":"სსკ-ის 70-ე მუხლის შესაბამისად, მსჯავრდებული, რომელსაც განაჩენის გამოტანის შემდეგ განუვითარდა მძიმე დაავადება, რაც ხელს უშლის სასჯელის მოხდას, შეიძლება გათავისუფლდეს სასჯელის შემდგომი მოხდისაგან.","law_article":"მუხლი 70"},{"text":"რა ვადებში თავისუფლდება მსჯავრდებული სასჯელის მოხდისაგან გამამტყუნებელი განაჩენის აღუსრულებლობის (ხანდაზმულობის) გამო ნაკლებად მძიმე დანაშაულისთვის სსკ-ის 71-ე მუხლის 1-ლი ნაწილის მიხედვით?","options":["A. 6 წელი, თუ გამამტყუნებელი განაჩენი არ აღსრულდა ნაკლებად მძიმე დანაშაულისათვის მსჯავრდებისას.","B. 2 წელი, თუ გამამტყუნებელი განაჩენი არ აღსრულდა ნაკლებად მძიმე დანაშაულისათვის მსჯავრდებისას.","C. 5 წელი, თუ გამამტყუნებელი განაჩენი არ აღსრულდა ნაკლებად მძიმე დანაშაულისათვის მსჯავრდებისას.","D. 10 წელი, თუ გამამტყუნებელი განაჩენი არ აღსრულდა ნაკლებად მძიმე დანაშაულისათვის მსჯავრდებისას."],"correct_option":"A","explanation":"სსკ-ის 71-ე მუხლის 1-ლი ნაწილის „ა“ ქვეპუნქტის მიხედვით, მსჯავრდებული თავისუფლდება სასჯელის მოხდისაგან, თუ გამამტყუნებელი განაჩენი არ აღსრულებულა 6 წლის განმავლობაში ნაკლებად მძიმე დანაშაულისათვის მსჯავრდებისას.","law_article":"მუხლი 71, ნაწილი 1, ქვეპუნქტი ა"},{"text":"რა ვადებში თავისუფლდება მსჯავრდებული სასჯელის მოხდისაგან განაჩენის აღუსრულებლობის გამო მძიმე და განსაკუთრებით მძიმე დანაშაულზე სსკ-ის 71-ე მუხლის 1-ლი ნაწილის შესაბამისად?","options":["A. 10 წელი – მძიმე დანაშაულისათვის; 25 წელი – განსაკუთრებით მძიმე დანაშაულისათვის.","B. 10 წელი – მძიმე დანაშაულისათვის; 15 წელი – განსაკუთრებით მძიმე დანაშაულისათვის.","C. 8 წელი – მძიმე დანაშაულისათვის; 20 წელი – განსაკუთრებით მძიმე დანაშაულისათვის.","D. 12 წელი – მძიმე დანაშაულისათვის; 25 წელი – განსაკუთრებით მძიმე დანაშაულისათვის."],"correct_option":"A","explanation":"სსკ-ის 71-ე მუხლის 1-ლი ნაწილის „ბ“ და „გ“ ქვეპუნქტების მიხედვით, განაჩენის აღუსრულებლობის ხანდაზმულობა შეადგენს 10 წელს მძიმე დანაშაულისთვის და 25 წელს განსაკუთრებით მძიმე დანაშაულისთვის.","law_article":"მუხლი 71, ნაწილი 1, ქვეპუნქტები ბ, გ"},{"text":"ვის მიერ აცხადდება ამნისტია და რა სამართლებრივი შედეგები შეიძლება მოჰყვეს მას სსკ-ის 72-ე მუხლის მიხედვით?","options":["A. აცხადებს საქართველოს პარლამენტი; პირს შეიძლება შეუმცირდეს სასჯელი, შეეცვალოს უფრო მსუბუქი სასჯელით ან გათავისუფლდეს პასუხისმგებლობისგან/სასჯელისგან.","B. აცხადებს საქართველოს პრეზიდენტი; პირი თავისუფლდება მხოლოდ სასჯელის მოხდისაგან, ხოლო ნასამართლობა უნარჩუნდება.","C. აცხადებს საქართველოს იუსტიციის მინისტრი; პირს ეხსნება ნასამართლობა და უქმდება დამატებითი სასჯელი.","D. აცხადებს საქართველოს უზენაესი სასამართლო; პირი თავისუფლდება სისხლისსამართლებრივი პასუხისმგებლობისგან ზიანის ანაზღაურების პირობით."],"correct_option":"A","explanation":"სსკ-ის 72-ე მუხლის თანახმად, ამნისტიას აცხადებს საქართველოს პარლამენტი ინდივიდუალურად განუსაზღვრელი პირების მიმართ. ამნისტიით პირი შეიძლება გათავისუფლდეს პასუხისმგებლობისგან ან სასჯელისგან, შეუმცირდეს სასჯელი ან შეეცვალოს უფრო მსუბუქით.","law_article":"მუხლი 72"},{"text":"ვის მიერ ხორციელდება შეწყალება და ვის მიმართ გამოიყენება იგი სსკ-ის 73-ე მუხლის მიხედვით?","options":["A. ახორციელებს საქართველოს პრეზიდენტი ინდივიდუალურად განსაზღვრული პირის მიმართ.","B. ახორციელებს საქართველოს პარლამენტი ინდივიდუალურად განსაზღვრული ჯგუფის მიმართ.","C. ახორციელებს იუსტიციის მინისტრი სპეციალური კომისიის რეკომენდაციით.","D. ახორციელებს საქართველოს პრემიერ-მინისტრი სასჯელაღსრულების ორგანოს წარდგინებით."],"correct_option":"A","explanation":"სსკ-ის 73-ე მუხლის პირველი ნაწილის თანახმად, შეწყალებას ახორციელებს საქართველოს პრეზიდენტი ინდივიდუალურად განსაზღვრული პირის მიმართ.","law_article":"მუხლი 73, ნაწილი 1"},{"text":"რა სამართლებრივი სტატუსი აქვს პირს ნასამართლობის მქონედ მიჩნევის პერიოდში სსკ-ის 79-ე მუხლის 1-ლი ნაწილის შესაბამისად?","options":["A. ნასამართლობა მხედველობაში მიიღება სისხლისსამართლებრივი პასუხისმგებლობის, დანაშაულის კვალიფიკაციისა და სასჯელის დანიშვნისას.","B. ნასამართლობა იწვევს სამოქალაქო უფლებების სრულ შეზღუდვას და საჯარო სამსახურში დასაქმების მუდმივ აკრძალვას.","C. ნასამართლობა გავლენას ახდენს მხოლოდ განმეორებითი დანაშაულის ჩადენისას სასჯელის ზომის განსაზღვრაზე.","D. ნასამართლობა ავტომატურად ზრდის ახალი დანაშაულისათვის გათვალისწინებული სანქციის ზედა ზღვარს ორჯერ."],"correct_option":"A","explanation":"სსკ-ის 79-ე მუხლის 1-ლი ნაწილის თანახმად, ნასამართლობა მხედველობაში მიიღება სისხლისსამართლებრივი პასუხისმგებლობის, დანაშაულის კვალიფიკაციისა და სისხლისსამართლებრივი ზემოქმედების ღონისძიების განსაზღვრისას.","law_article":"მუხლი 79, ნაწილი 1"},{"text":"როდის ითვლება პირი ნასამართლობის არმქონედ სსკ-ის 79-ე მუხლის მე-2 ნაწილის მიხედვით?","options":["A. პირი, რომელიც გათავისუფლდა სასჯელისაგან, ითვლება ნასამართლობის არმქონედ.","B. პირი, რომელმაც მოიხადა ჯარიმა ან საზოგადოებისათვის სასარგებლო შრომა, 6 თვის შემდეგ ითვლება ნასამართლობის არმქონედ.","C. პირი, რომელსაც დაენიშნა პირობითი მსჯავრი, გამოსაცდელი ვადის გასვლისთანავე ითვლება ნასამართლობის არმქონედ ავტომატურად.","D. პირი, რომელმაც სრულად აანაზღაურა მიყენებული ზიანი განაჩენის აღსრულების დღიდან."],"correct_option":"A","explanation":"სსკ-ის 79-ე მუხლის მე-2 ნაწილის თანახმად, პირი, რომელიც გათავისუფლდა სასჯელისაგან, ითვლება ნასამართლობის არმქონედ.","law_article":"მუხლი 79, ნაწილი 2"},{"text":"რა ვადაში ქარწყლდება ნასამართლობა პირობით მსჯავრდებული პირისათვის სსკ-ის 79-ე მუხლის მე-3 ნაწილის „ა“ ქვეპუნქტის შესაბამისად?","options":["A. გამოსაცდელი ვადის გასვლისთანავე.","B. გამოსაცდელი ვადის გასვლიდან 1 წლის შემდეგ.","C. გამოსაცდელი ვადის ნახევრის გასვლისთანავე.","D. განაჩენის კანონიერ ძალაში შესვლიდან 6 თვის შემდეგ."],"correct_option":"A","explanation":"სსკ-ის 79-ე მუხლის მე-3 ნაწილის „ა“ ქვეპუნქტის მიხედვით, პირობით მსჯავრდებულს ნასამართლობა გაუქარწყლდება გამოსაცდელი ვადის გასვლისთანავე.","law_article":"მუხლი 79, ნაწილი 3, ქვეპუნქტი ა"},{"text":"რა ვადაში ქარწყლდება ნასამართლობა თავისუფლების აღკვეთაზე უფრო მსუბუქი სასჯელით მსჯავრდებული პირისათვის სსკ-ის 79-ე მუხლის მე-3 ნაწილის „ბ“ ქვეპუნქტის მიხედვით?","options":["A. სასჯელის მოხდიდან 1 წლის გასვლის შემდეგ.","B. სასჯელის მოხდიდან 6 თვის გასვლის შემდეგ.","C. სასჯელის მოხდიდან 2 წლის გასვლის შემდეგ.","D. სასჯელის დაკისრების დღიდან 1 წლის გასვლის შემდეგ."],"correct_option":"A","explanation":"სსკ-ის 79-ე მუხლის მე-3 ნაწილის „ბ“ ქვეპუნქტის შესაბამისად, თავისუფლების აღკვეთაზე უფრო მსუბუქი სასჯელით მსჯავრდებულს ნასამართლობა გაუქარწყლდება სასჯელის მოხდიდან 1 წლის გასვლის შემდეგ.","law_article":"მუხლი 79, ნაწილი 3, ქვეპუნქტი ბ"},{"text":"რა ვადებში ქარწყლდება ნასამართლობა ვადიანი თავისუფლების აღკვეთით მსჯავრდებული პირებისათვის ნაკლებად მძიმე, მძიმე და განსაკუთრებით მძიმე დანაშაულებზე სსკ-ის 79-ე მუხლის მე-3 ნაწილის მიხედვით?","options":["A. ნაკლებად მძიმე დანაშაულზე – 3 წელი; მძიმე დანაშაულზე – 6 წელი; განსაკუთრებით მძიმე დანაშაულზე – 8 წელი (სასჯელის მოხდიდან).","B. ნაკლებად მძიმე დანაშაულზე – 2 წელი; მძიმე დანაშაულზე – 5 წელი; განსაკუთრებით მძიმე დანაშაულზე – 10 წელი (სასჯელის მოხდიდან).","C. ნაკლებად მძიმე დანაშაულზე – 1 წელი; მძიმე დანაშაულზე – 3 წელი; განსაკუთრებით მძიმე დანაშაულზე – 5 წელი (სასჯელის მოხდიდან).","D. ნაკლებად მძიმე დანაშაულზე – 3 წელი; მძიმე დანაშაულზე – 5 წელი; განსაკუთრებით მძიმე დანაშაულზე – 7 წელი (სასჯელის მოხდიდან)."],"correct_option":"A","explanation":"სსკ-ის 79-ე მუხლის მე-3 ნაწილის „გ“, „დ“ და „ე“ ქვეპუნქტების მიხედვით, ნასამართლობის გაქარწყლების ვადებია: ნაკლებად მძიმე დანაშაულზე – 3 წელი; მძიმე დანაშაულზე – 6 წელი; განსაკუთრებით მძიმე დანაშაულზე – 8 წელი სასჯელის მოხდის შემდეგ.","law_article":"მუხლი 79, ნაწილი 3, ქვეპუნქტები გ, დ, ე"},{"text":"რა სამართლებრივი შედეგი მოჰყვება ნასამართლობის გაქარწყლებას ან მოხსნას სსკ-ის 79-ე მუხლის მე-6 ნაწილის შესაბამისად?","options":["A. ნასამართლობის გაქარწყლება ან მოხსნა გააქარწყლებს ნასამართლობიდან გამომდინარე ყველა სამართლებრივ შედეგს.","B. ნასამართლობის გაქარწყლება აუქმებს ძირითად სასჯელს, მაგრამ ინარჩუნებს ჩამორთმეულ სპეციალურ უფლებებს.","C. ნასამართლობის გაქარწყლება გამორიცხავს პასუხისმგებლობას მხოლოდ ნაკლებად მძიმე დანაშაულის განმეორებით ჩადენისას.","D. ნასამართლობის გაქარწყლება იწვევს პირის მონაცემების სრულ ამოშლას საინფორმაციო ბაზიდან ავტომატურ რეჟიმში."],"correct_option":"A","explanation":"სსკ-ის 79-ე მუხლის მე-6 ნაწილის თანახმად, ნასამართლობის გაქარწყლება ან მოხსნა გააქარწყლებს ნასამართლობიდან გამომდინარე ყველა სამართლებრივ შედეგს.","law_article":"მუხლი 79, ნაწილი 6"},{"text":"რომელ პირებს მიენიჭებათ არასრულწლოვანთა სისხლისსამართლებრივი პასუხისმგებლობის სპეციალური წესები სსკ-ის 80-ე მუხლის მიხედვით?","options":["A. პირს, რომელსაც დანაშაულის ჩადენამდე შეუსრულდა 14 წელი, მაგრამ არ შეუსრულებია 18 წელი.","B. პირს, რომელსაც დანაშაულის ჩადენამდე შეუსრულდა 12 წელი, მაგრამ არ შეუსრულებია 16 წელი.","C. პირს, რომელსაც განაჩენის გამოტანის მომენტში არ შეუსრულებია 18 წელი.","D. პირს, რომელსაც დანაშაულის ჩადენამდე შეუსრულდა 14 წელი, მაგრამ არ შეუსრულებია 21 წელი."],"correct_option":"A","explanation":"სსკ-ის 80-ე მუხლის თანახმად, არასრულწლოვნად ითვლება პირი, რომელსაც დანაშაულის ჩადენამდე შეუსრულდა 14 წელი, მაგრამ არ შეუსრულებია 18 წელი.","law_article":"მუხლი 80"},{"text":"რომელი სასჯელები შეიძლება დაენიშნოს არასრულწლოვანს სსკ-ის 81-ე მუხლის შესაბამისად?","options":["A. ჯარიმა, საზოგადოებისათვის სასარგებლო შრომა, შინაპატიმრობა, ვადიანი თავისუფლების აღკვეთა.","B. გამასწორებელი სამუშაო, ჯარიმა, ვადიანი თავისუფლების აღკვეთა, უვადო თავისუფლების აღკვეთა.","C. შინაპატიმრობა, სამხედრო პირის სამსახურებრივი შეზღუდვა, ჯარიმა, თავისუფლების აღკვეთა.","D. საზოგადოებისათვის სასარგებლო შრომა, ჯარიმა, ქონების ჩამორთმევა, თავისუფლების აღკვეთა."],"correct_option":"A","explanation":"სსკ-ის 81-ე მუხლის მიხედვით, არასრულწლოვანს სასჯელის სახით შეიძლება დაენიშნოს: ჯარიმა, საზოგადოებისათვის სასარგებლო შრომა, შინაპატიმრობა, ვადიანი თავისუფლების აღკვეთა.","law_article":"მუხლი 81"},{"text":"რა პირობით შეიძლება დაენიშნოს ჯარიმა არასრულწლოვანს სსკ-ის 82-ე მუხლის მიხედვით?","options":["A. თუ არასრულწლოვანს აქვს დამოუკიდებელი შემოსავალი ან ქონება, რომელზედაც შეიძლება მიექცეს გადახდევინება.","B. თუ არასრულწლოვნის მშობლები ან კანონიერი წარმომადგენლები წერილობით აიღებენ ჯარიმის გადახდის ვალდებულებას.","C. თუ არასრულწლოვანმა ჩაიდინა ფინანსური ხასიათის ნაკლებად მძიმე დანაშაული.","D. ჯარიმა არასრულწლოვანს ენიშნება ნებისმიერ შემთხვევაში, ხოლო გადაუხდელობისას იფარება შრომით."],"correct_option":"A","explanation":"სსკ-ის 82-ე მუხლის მიხედვით, არასრულწლოვანს ჯარიმა შეიძლება დაენიშნოს მხოლოდ იმ შემთხვევაში, თუ მას აქვს დამოუკიდებელი შემოსავალი ან ქონება.","law_article":"მუხლი 82"},{"text":"რა მაქსიმალური ვადით შეიძლება დაენიშნოს არასრულწლოვანს საზოგადოებისათვის სასარგებლო შრომა სსკ-ის 83-ე მუხლის შესაბამისად?","options":["A. 40-დან 400 საათამდე ვადით.","B. 20-დან 200 საათამდე ვადით.","C. 60-დან 600 საათამდე ვადით.","D. 100-დან 800 საათამდე ვადით."],"correct_option":"A","explanation":"სსკ-ის 83-ე მუხლის მიხედვით, არასრულწლოვანს საზოგადოებისათვის სასარგებლო შრომა განესაზღვრება 40-დან 400 საათამდე ვადით.","law_article":"მუხლი 83"},{"text":"როგორ განისაზღვრება თავისუფლების აღკვეთის ვადა არასრულწლოვანისათვის სასჯელის დანიშვნისას სსკ-ის 88-ე მუხლის მიხედვით?","options":["A. არასრულწლოვანს თავისუფლების აღკვეთა განესაზღვრება შესაბამისი მუხლით გათვალისწინებული სასჯელის ვადის ნახევრით შეცირებით.","B. არასრულწლოვანს თავისუფლების აღკვეთა განესაზღვრება მაქსიმუმ 10 წლის ვადით, მიუხედავად დანაშაულის სიმძიმისა.","C. არასრულწლოვანს თავისუფლების აღკვეთა მცირდება 1/3-ით, ხოლო 16 წლამდე ასაკის პირს – 1/2-ით.","D. არასრულწლოვანს თავისუფლების აღკვეთა ენიშნება მხოლოდ განსაკუთრებით მძიმე დანაშაულისთვის 5-დან 15 წლამდე."],"correct_option":"A","explanation":"სსკ-ის 88-ე მუხლის მიხედვით, არასრულწლოვანს თავისუფლების აღკვეთა განესაზღვრება იმ ვადის ნახევრით შემცირებით, რაც გათვალისწინებულია კოდექსის შესაბამისი მუხლით.","law_article":"მუხლი 88"},{"text":"რა ვადებში მცირდება ხანდაზმულობის ვადები არასრულწლოვანთა მიმართ სისხლისსამართლებრივი პასუხისმგებლობისას სსკ-ის 90-ე მუხლის შესაბამისად?","options":["A. სისხლისსამართლებრივი პასუხისმგებლობისა და გამამტყუნებელი განაჩენის აღსრულების ხანდაზმულობის ვადები არასრულწლოვანის მიმართ განახევრდება.","B. ხანდაზმულობის ვადები მცირდება 1/3-ით ნაკლებად მძიმე დანაშაულზე და 1/2-ით მძიმე დანაშაულზე.","C. ხანდაზმულობის ვადები არასრულწლოვნების მიმართ შეადგენს უპირობოდ 3 წელს ნაკლებად მძიმე და 5 წელს მძიმე დანაშაულზე.","D. ხანდაზმულობის ვადები არასრულწლოვნების მიმართ არ იცვლება და მოქმედებს საერთო წესი."],"correct_option":"A","explanation":"სსკ-ის 90-ე მუხლის შესაბამისად, არასრულწლოვანთა მიმართ სისხლისსამართლებრივი პასუხისმგებლობისა და გამამტყუნებელი განაჩენის აღსრულების ხანდაზმულობის ვადები განახევრდება.","law_article":"მუხლი 90"}]$questions$::jsonb)
  loop
    select id into v_question_id
    from public.questions
    where law_id = v_law_id
      and text = r.question->>'text';

    if v_question_id is null then
      select id into v_article_id
      from public.law_articles
      where law_id = v_law_id
        and article_number = regexp_replace(
          r.question->>'law_article',
          '^(მუხლი[[:space:]]+[^,[:space:]]+).*$',
          '\1'
        );

      insert into public.questions (
        category_id, subcategory_id, law_id, primary_law_article_id, text, difficulty,
        explanation, law_name, law_article, source_url, law_version_date,
        needs_review, is_prime, is_published
      )
      values (
        v_category_id, v_subcategory_id, v_law_id, v_article_id,
        r.question->>'text', 'hard', r.question->>'explanation',
        'საქართველოს სისხლის სამართლის კოდექსი', r.question->>'law_article',
        v_source_url, v_version_date, true, false, false
      )
      returning id into v_question_id;

      insert into public.question_options (question_id, option_text, is_correct, sort_order)
      select
        v_question_id,
        option.value,
        case option.ordinality
          when 1 then r.question->>'correct_option' = 'A'
          when 2 then r.question->>'correct_option' = 'B'
          when 3 then r.question->>'correct_option' = 'C'
          when 4 then r.question->>'correct_option' = 'D'
        end,
        option.ordinality
      from jsonb_array_elements_text(r.question->'options') with ordinality as option(value, ordinality);

      if v_article_id is not null then
        insert into public.question_law_articles (question_id, law_article_id, is_primary)
        values (v_question_id, v_article_id, true)
        on conflict (question_id, law_article_id) do nothing;
      end if;
    end if;
  end loop;
end $$;
